const payload = $input.first().json;

// GitHub Trigger wraps the webhook payload as a JSON string in "body"
let issue = {};
let repo = {};

try {
  const webhookBody = typeof payload.body === 'string'
    ? JSON.parse(payload.body)
    : payload.body || {};

  issue = webhookBody.issue || {};
  repo = webhookBody.repository || {};
} catch (e) {
  // parse failed, keep empty objects
}

// Fallback: extract repo from repository_url if repo object is empty
// URL format: https://api.github.com/repos/{owner}/{repo}
let repoFullName = repo.full_name || '';
if (!repoFullName && issue.repository_url) {
  const match = issue.repository_url.match(/repos\/([^/]+\/[^/]+)/);
  if (match) repoFullName = match[1];
}

const rawBody = issue.body;
let bodyText = '';

if (rawBody && typeof rawBody === 'string') {
  bodyText = rawBody.substring(0, 2000);
} else {
  bodyText = '';
}

const issueData = {
  issue_number: issue.number || 0,
  title: String(issue.title || 'No title'),
  body: bodyText,
  url: String(issue.html_url || ''),
  author: String(issue.user?.login || 'unknown'),
  labels: (issue.labels || []).map(l => typeof l === 'string' ? l : String(l.name || '')),
  created_at: String(issue.created_at || new Date().toISOString()),
  repo_full_name: repoFullName
};

return [{ json: issueData }];

const item = $input.first().json;
const issueData = $('Extract GitHub Issue Data').first().json;

// Case 1: Notion query failed (API error, timeout, etc.)
// item will have error-related fields, no "id"
// → pass through, still triage the issue
if (item.error || item.code || item.message) {
  return [{ json: { ...issueData, duplicate_check: 'error' } }];
}

// Case 2: Notion returned empty object [{}] from "Always Output Data"
// No match found → new issue → triage
if (!item.id) {
  return [{ json: { ...issueData, duplicate_check: 'passed' } }];
}

// Case 3: Notion found a matching page (has "id" field)
// Already triaged → skip by returning empty
return [];

const llmOutput = $input.first().json;
const issueData = $('Extract GitHub Issue Data').first().json;

const result = {
  category: 'other',
  priority: 'medium',
  summary: '',
  suggested_labels: []
};

try {
  // n8n Chain LLM returns { output: "..." } or { text: "..." }
  let raw = llmOutput.output || llmOutput.text || '';

  // Strip thinking tags (Qwen 3 sometimes adds these)
  raw = raw.replace(/&lt;think&gt;[\s\S]*?<\/think>/gi, '').trim();

  // Extract JSON block from response
  const jsonMatch = raw.match(/\{[\s\S]*?\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);

    const validCategories = ['bug', 'feature', 'question', 'documentation', 'other'];
    const validPriorities = ['high', 'medium', 'low'];

    result.category = validCategories.includes(parsed.category) ? parsed.category : 'other';
    result.priority = validPriorities.includes(parsed.priority) ? parsed.priority : 'medium';
    result.summary = typeof parsed.summary === 'string' ? parsed.summary.substring(0, 200) : '';
    result.suggested_labels = Array.isArray(parsed.suggested_labels)
      ? parsed.suggested_labels.slice(0, 3).map(l => String(l).toLowerCase())
      : [];
  }
} catch (e) {
  // Parsing failed — keep defaults
}

return [{
  json: {
    issue_number: issueData.issue_number,
    title: issueData.title,
    url: issueData.url,
    author: issueData.author,
    created_at: issueData.created_at,
    repo_full_name: issueData.repo_full_name,
    category: result.category,
    priority: result.priority,
    summary: result.summary,
    suggested_labels: result.suggested_labels,
    source: 'ai'
  }
}];

const issueData = $('Extract GitHub Issue Data').first().json;

return [{
  json: {
    issue_number: issueData.issue_number,
    title: issueData.title,
    url: issueData.url,
    author: issueData.author,
    created_at: issueData.created_at,
    repo_full_name: issueData.repo_full_name,
    category: 'other',
    priority: 'medium',
    summary: 'AI triage failed — manual review needed',
    suggested_labels: [],
    source: 'fallback'
  }
}];

const notion = $input.first().json;
const issue = $('Extract GitHub Issue Data').first().json;

const category = notion.property_category || 'unknown';
const priority = notion.property_priority || 'unknown';
const summary = notion.property_summary || '';
const suggestedLabels = notion.property_suggested_labels || '';
const source = notion.property_source || 'ai';

let body = '🤖 **Auto-Triage Result**\n';
body += '- **Category:** ' + category + '\n';
body += '- **Priority:** ' + priority + '\n';
body += '- **Summary:** ' + summary + '\n';

if (suggestedLabels) {
  body += '- **Suggested labels:** ' + suggestedLabels + '\n';
}

if (source === 'fallback') {
  body += '\n⚠️ _AI triage was unavailable. This was assigned default values._\n';
}

body += '\n_Triaged by n8n automation_';

return [{
  json: {
    owner: issue.repo_full_name.split('/')[0],
    repository: issue.repo_full_name.split('/')[1],
    issue_number: issue.issue_number,
    comment_body: body
  }
}];
